	// We ask for one return value and protect the call so that a Lua
	// panic is converted into a Go error.
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("error while executing calculate_final_price: %w", err)
	}

	// Retrieve the returned value.
	retVal := L.Get(-1)
	L.Pop(1) // Remove the result from the stack.

	// The function must return a number.
	if retVal.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	// Convert Lua number to Go float64.
	return float64(retVal.(lua.LNumber)), nil
}

